const body = $input.first().json;
const types = { 'cash': 'Cash Buyer', 'landlord': 'Landlord', 'developer': 'Developer', 'builder': 'Builder', 'flipper': 'Flipper' };
const key = (body.buyer_type || '').toLowerCase();
return [{ json: { ...body, buyer_type: types[key] || 'Cash Buyer', lead_type: 'Buyer', source: body.source || 'Web Form', status: 'New' } }];

